const item = $input.first().json;

let label = "Low";
if (item.score >= 80) label = "High Quality";
else if (item.score >= 50) label = "Medium";
else if (item.score === null || item.score === undefined) label = "Unverified";

return [{
  json: {
    label: label,
    full_name: item.full_name ?? "",
    email: item.email ?? "",
    company: item.company ?? "",
    score: item.score ?? 0,
    linkedin_url: item.linkedin_url ?? null,
    received_at: item.received_at,
    body: {
      parent: {
        database_id: "37087922-0078-80d5-a5a9-f147b7f48cc2"
      },
      properties: {
        Name: {
          title: [{ text: { content: item.full_name ?? "" } }]
        },
        Company: {
          rich_text: [{ text: { content: item.company ?? "" } }]
        },
        Score: {
          number: item.score ?? 0
        },
        LinkedIn: {
          url: item.linkedin_url ?? null
        },
        Status: {
          select: { name: "new" }
        },
        "Received At": {
          date: { start: item.received_at }
        }
      }
    }
  }
}];
